var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이봐! 대체 어딜 가는 거야?","JPN":"もう、いったいどこ行くのよ！","ENG":"Hey! Where do you think you're going?","TWN":"喂！你到底要去哪啊？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"와? 알면 따라오게?","JPN":"なんや？　教えたらついてくんのか？","ENG":"What? You're gonna follow me?","TWN":"什麼？想知道的話就跟上來？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당연하지! 난 아직 당신과 결판을 짓지 못했다고!","JPN":"当然でしょ！　私はまだあんたと決着をつけてないもの！","ENG":"Duh! I still have unfinished business with you!","TWN":"當然了！我還沒有和你決一勝負呢！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 참 오래도 가네. 내 덕에 나이트 잡고 랭커 된 건 잊었나?","JPN":"あはは、まだ引きずってるんやな。ウチのおかげでナイト倒してランカーになったの、忘れたんか？","ENG":"Ah hah hah, you're so stubborn. Did ya forget that you entered the top ranks because I helped ya defeat Knight?","TWN":"哈哈哈，真是難纏啊。難道忘了因為我打敗了騎士才能擠進前段班嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니거든! 내가 잘해서 여기까지 온 거거든?!","JPN":"違うわよ！　私が強いからここまで来たのよ！","ENG":"That's not true! I made it all the way here by myself!","TWN":"才不是呢！我是靠自己的本事爭取的！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"진짜 성격 하고는, 아까 그 삼총사들이 대신 사과해 주지 않았으면 큰일났을 기다.","JPN":"ホンマ、ええ性格しとるな。さっきの3人が代わりに謝ってくれへんかったら、大事になっとったはずやで。","ENG":"Geez. If the trio didn't apologize for ya, you would've been toast.","TWN":"要不是剛才那三人組替你道歉，事情可就麻煩了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"필요 없어! 그깟 놈들이 뭐가 무섭다고!","JPN":"どうでもいいわ！　あんな奴ら怖くない！","ENG":"I didn't need to apologize! I'm not afraid of them!","TWN":"我不怕！那些傢伙有什麼好怕的！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……니는 아까 개들이랑 싸웠을 때 뭔가 못 느꼈나?","JPN":"……さっきあいつらと戦った時、おかしいと思わへんかったか？","ENG":"...Didn't ya feel something odd when you were fightin' them?","TWN":"……你剛才和那些傢伙戰鬥時，有沒有感覺到什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아무리 아티팩트의 힘이라지만…… 너무 강하지 않았나?","JPN":"いくらアーティファクトの力借りてるとはいえ……強すぎたやろ？","ENG":"Even with the power of the Artifact... don't ya think it was a little too strong?","TWN":"雖然是神器的力量……但也太強了吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그러고 보니…… 무슨 치트라도 쓴 것 같긴 했지……","JPN":"い、言われてみれば……チートでも使ったような感じだった……","ENG":"C-come to think of it... it did feel like they were cheating in a way...","TWN":"這，這麼說來……好像用了什麼作弊手法……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"불안한 마음이 가시질 않네. 인자 놀 수만은 없겠다.","JPN":"この不安感……どうしても拭いきれへんねん。のんびりしてられんな。","ENG":"I can't seem to shake that feelin' off. Guess I can't just fool around like the ol' days anymore.","TWN":"不安的心情揮之不去，現在不能再悠閒下去了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……예전부터 궁금했는데 말야, 당신 대체 뭐 하는 사람이야?","JPN":"……前から気になってたけど、あんたっていったい何者なの？","ENG":"...I've been meaning to ask, but who are you really?","TWN":"……我一直很好奇，你到底是做什麼的？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"응? 그건 왜?","JPN":"ん？　なんで気になるん？","ENG":"Hmm? Why do ya wanna know?","TWN":"嗯？怎麼了？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"처음 봤을 땐, 나랑 비슷한 나이라고 생각했어.","JPN":"初めて会った時は、私と同じぐらいの年齢だと思った。","ENG":"When I first saw you, I thought you were around my age.","TWN":"第一次見面時，我以為你和我年紀差不多。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"근데 말투도 그렇고, 날 대하는 것도 무슨 어린애 대하듯이 하잖아.","JPN":"でも話す内容もそうだし、私のことも子ども扱いするし。","ENG":"But you talk to me and treat me as if I'm a child.","TWN":"但是你的語氣和對待我的態度，就像對待小孩子一樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"빨리 말해. 당신 정체가 뭐야?","JPN":"早く明かしなさいよ。あんたの正体。","ENG":"So tell me. Who are you?","TWN":"快說，你到底是什麼人？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……듣고 싶나?","JPN":"……聞きたいんか？","ENG":"...Ya really wanna know?","TWN":"……想聽嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"후회…… 안 할 자신 있나?","JPN":"後悔せえへん自信ある？","ENG":"Are ya certain... ya won't regret it?","TWN":"你確定……不會後悔嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이런다고 내가 겁먹을 것 같아?!","JPN":"そ、そんなこと言ったら私が怯えるとでも思う？","ENG":"Y-you think that's going to scare me off?!","TWN":"你，你以為我會怕嗎？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"알았다. 그럼 따라온나.","JPN":"わかったわ。ほんならついて来いや。","ENG":"Aight. Follow me.","TWN":"知道了，那就跟上來吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무, 무슨 얘길 하려는 거지……?","JPN":"な、何を話すつもり……？","ENG":"W-what's she going to say...?","TWN":"你，你想說什麼……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하! 그때는 진짜 깜짝 놀랐다 아이가!","JPN":"あはは！　あの時はほんまにびっくりしたで！","ENG":"Ah hah hah! It was a huge deal back then!","TWN":"哈哈哈！那時候真的嚇了一跳啊！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L40_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내가 장난으로 다인이 머리에다 술을 부운 적이 있었는데, 금마 그렇게 화난 모습은 내 처음 봤다!","JPN":"ふざけてタエの頭に酒かけたことあるけど、あいつがあんなに怒る姿は初めて見たわ！","ENG":"I poured alcohol on Dain's head as a joke, and it was the first time I ever saw her that angry!","TWN":"有一次我開玩笑把酒倒在了妲茵的頭上，那傢伙生氣的樣子我還是第一次見到！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그때 다인이가 뭐랬는지 아나?","JPN":"あの時、タエがなんて言うたと思う？","ENG":"Do ya know what she said to me?","TWN":"你知道那時候妲茵說了什麼嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"후후, 리네야. 그 술버릇을 고쳐주려면 하루 종일 참새 지저귀는 소릴 들려줘야겠네?","JPN":"ふふ、マリちゃん。あなたのその酒癖を直すためには、朝から晩まで小言をずーっと言い聞かせなきゃいけないみたいね。","ENG":"\\"Fu fuu, Rinae. I think I'll have to make you listen to sparrows chirping all day to fix that nasty drunken behavior of yours.\\"","TWN":"呵呵，璃奈，要想改掉你的酒品，是不是要天天提醒你呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L46_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그, 그러니까 보라는 또 뭐랬는지 아나?","JPN":"そしたらシホがこう言うたんや。","ENG":"Th-then, Bora said–","TWN":"然後寶拉說。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"사과해…… 리네야.","JPN":"謝って……マリ。","ENG":"\\"Apologize... Rinae.\\"","TWN":"道歉吧……璃奈。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"너무 심했어……. 장난.","JPN":"度を越してる……おふざけが。","ENG":"\\"You went... too far.\\"","TWN":"確實有點過分了……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하하핫!! 방금 내 완전 금마랑 똑같지 않았나?","JPN":"あはははは！！　今のモノマネ、めっちゃ似とったやろ？","ENG":"A ha ha ha ha!! I sounded just like her right now, didn't I?","TWN":"哈哈哈哈！！剛才我是不是和那傢伙一模一樣？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"허…… 헣……!","JPN":"は、はは……！","ENG":"Ha… ha…","TWN":"呼…… 呼……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하~ 오랜만에 옛날얘기 좀 하다 보니 시간 가는 줄 몰랐네.","JPN":"はあ～！　久しぶりに昔話したら、時間を忘れてもうたな。","ENG":"Ah... I lost track of time talkin' about the good ol' times.","TWN":"哈～好久沒聊以前的事了，不知不覺時間就過去了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아, 그렇지…… 우리 뭔 얘기하고 있었더라?","JPN":"あ、そうやな……なんの話しとったっけ？","ENG":"Oh, right... What were we talkin' about?","TWN":"啊，對了……我們剛剛在說什麼？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 장난해?! 엄청 진지한 얘길 하려는가 싶더니 뭐 하자는 건데?","JPN":"ふざけないでよ！　すごい真剣な顔しといて、今の話は何なのよ！","ENG":"Are you kidding me?! I thought you were going to say something serious!","TWN":"你開什麼玩笑？！剛才還說得那麼認真，現在又是怎麼回事？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이젠 말해줄 때도 됐잖아! 계속 질질 끌기만 할 거야?","JPN":"そろそろ話してくれてもいいでしょ！　引っ張りすぎ！","ENG":"How much longer are you going to drag this out?! Now, tell me!","TWN":"現在該告訴我了吧！你還要一直拖下去嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내는 있제, 한 마디로 정의하긴 좀 그렇고 음…….","JPN":"あのな、一言で定義するんは難しくて、うーん……","ENG":"Ya know, it's kinda hard to describe who I am in one word. Um...","TWN":"我嘛，很難用一句話定義，嗯……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"최고의 아티팩트 수집가, 미리네★트레져헌터! 라고나 할까……?","JPN":"最高のアーティファクト収集家、マリ★トレジャーハンター！　っちゅうとこかな？","ENG":"How 'bout, \\"the best Artifact collector, Mi Rinae★Treasure Hunter!\\"","TWN":"最強的人造神器收藏家，宓璃奈★尋寶獵人！這樣說……怎麼樣？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하…… 제대로 알려줄 생각은 처음부터 없었나 보네.","JPN":"はあ……最初からまともに話すつもりはなかったのね。","ENG":"*Sigh* I see that you never intended on telling me in the first place.","TWN":"哈……看來你從一開始就沒打算好好告訴我吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이만하면 충분하지, 깊이 관여하면 혼나요 혼나.","JPN":"これで十分やろ。深く関わったら後悔するで。","ENG":"Ain't that enough? You'll only get hurt if ya try to find out more 'bout me.","TWN":"這樣就夠了，知道太多也不好。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"동경하는 마음을 비춰주는 아티팩트…… 말만 들으면 좋은 물건이다.","JPN":"憧れの気持ちを映し出すアーティファクト……言葉だけ聞くと素敵やな。","ENG":"An Artifact that reflects one's admiration... Sure, it sounds like a great object.","TWN":"映照憧憬之心的神器……光聽名字就覺得是個好東西。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하지만 아티팩트는 전능한 게 아냐. 반드시 부작용이 있을기다.","JPN":"でもアーティファクトは全能じゃないんや。必ず何らかの副作用が伴う。","ENG":"But an Artifact ain't omnipotent. It's always accompanied with side effects.","TWN":"但是神器並不是萬能的，一定會有副作用。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"부작용? 아까 본 녀석들 때문에 그러는 거야?","JPN":"副作用？　さっきのやつらの話？","ENG":"Side effects? Is that why those idiots acted so strangely?","TWN":"副作用？是因為剛才看到的那些傢伙嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그뿐 아니라 심하면 현실과 구분을 못 하는 녀석들도 보였어.\xA0","JPN":"あいつらだけちゃう、現実との区別がつかんようになってるやつらもいた。\xA0","ENG":"It's not just them. I've seen a few who couldn't even tell reality apart.\xA0","TWN":"不僅如此，有些人甚至無法區分現實。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"카운터에 대한 동경. 이건 엘릭서 사건 때부터 늘 결말이 좋지 않았다.","JPN":"カウンターへの憧れ、これってエリクサー事件からあんまりいい結末にならへんのよな。","ENG":"An admiration toward Counters. This never ended well since the Elixir incident.","TWN":"對制裁者的憧憬。這從煉金藥劑事件開始就一直沒有好結果。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아티팩트의 힘을 받았다 해도, 일반인들은 카운터의 힘을 이해하지 못하고 있다.","JPN":"アーティファクトの力を借りたところで、一般人はカウンターの力を理解しきれへん。","ENG":"Even with the Artifact's power, non-Counters can't understand the power of Counters.","TWN":"即使得到了神器的力量，普通人也無法理解制裁者的力量。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"분명, 무의식적인 CRF 발현이 일어날 테고, 그렇게 됐다간…….","JPN":"無意識的なCRFの発現が起きるに決まっとる。そうなったら……","ENG":"They'll surely have an unconscious manifestation of CRF, and if that happens...","TWN":"顯然，會產生無意識的CRF顯現……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하…… 확실한 준비 없이 이카니까, 문제가 터지는 거 아니겠나?","JPN":"はあ……ちゃんとした準備も整わんうちに導入するから、こうなるんや。","ENG":"*Sigh* Well, problems like this happen 'cause we ain't got no safety measures.","TWN":"哀……因為沒有做好充分的準備，所以才會出問題，不是嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 서버를 닫던가 유저들을 내보내던가 하면 되잖아.","JPN":"じゃあサーバー閉じるかユーザーを追い出すかすればいいじゃない。","ENG":"Can't they just shut down the server or kick the players out?","TWN":"那就關閉伺服器或者讓玩家退出不就行了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그게…… 다 어른의 사정이란 게 있는 거겠지.","JPN":"それがな……大人の事情ってやつがあるんやろ。","ENG":"Well... There's more red tape than that.","TWN":"那個……大人們總是有他們的苦衷吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하아? 그딴 거 때문에 굳이 위험을 떠안겠다는 거야?!","JPN":"はあ？　そんなことでリスクを背負うってわけ？","ENG":"What? So, they're going to take the risk because of some bureaucracy?!","TWN":"蛤？就為了那種事非得冒險嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아티팩트와 동기화된 시스템을 함부로 닫았다간 또 다른 문제가 생길 수도 있으니까 하는 말이다.","JPN":"アーティファクトと同期化したシステムを無暗に閉じたら、また別の問題が起こるかもしれへん。","ENG":"I'm just sayin', other issues might occur when shutting down a system that's synced to an Artifact.","TWN":"我只是說，如果隨便關閉與神器同步的系統，可能會引發其他問題。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"한 번의 잘못된 선택으로, 더 큰 사태로 키울 수도 있는 일이다.","JPN":"1回の選択ミスで、さらに大事に発展する可能性があるんや。","ENG":"One wrong decision could lead to another catastrophe.","TWN":"一次錯誤的選擇，可能會導致更大的事情。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"나이엘, 보라한테 들었는데 니는 영웅이 되고 싶다 캤제?","JPN":"ナイエル、シホに聞いたで。あんたは英雄になりたいんやってな？","ENG":"Naielle, I heard from Bora that ya want to become a hero.","TWN":"奈爾，我聽寶拉說你想成為英雄，對吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"혹시…… 왜 영웅이 되고 싶은지 물어봐도 되나?","JPN":"英雄になりたい理由……聞いてもええか？","ENG":"Could ya... tell me why you wanna become one?","TWN":"……我可以問一下你為什麼想成為英雄嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"앙? 갑자기 그건 왜 물어?","JPN":"は？　なんでそんなこと急に聞くのよ。","ENG":"Huh? Why are you suddenly asking me that?","TWN":"嗯？你突然問這個幹嘛？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 내가 원래 후배한텐 정이 많이 가는 타입이거든.","JPN":"あはは、後輩には優しくしたいタイプなんや。","ENG":"Ah hah hah. I'm very affectionate toward Academy students.","TWN":"哈哈哈，我本來就對後輩很關心。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"지금 내 코스튬 있제? 사실 어릴 적에 다인이가 디자인해 줬거든.","JPN":"ウチのこのコスチューム、昔タエがデザインしてくれたんやで。","ENG":"This costume I'm wearin' now, Dain actually designed this for me when we were young.","TWN":"現在我穿的這套服裝，其實是小時候妲茵設計的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"히어로★스타라이트! 내도 한 때 순수하게 히어로를 동경했었지.","JPN":"ヒーロー★スターライト！　ウチも一時期は純粋な気持ちでヒーローに憧れてたんや。","ENG":"Hero★Starlight! I used to admire heroes like ya too.","TWN":"星光★英雄！我也曾經憧憬過當英雄。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 거의 헐벗은 복장이 무슨 영웅이야?","JPN":"ふん、ほとんど半裸な格好してどこがヒーローよ。","ENG":"Hmph. What kind of hero wears that skimpy outfit?","TWN":"哼，穿得這麼暴露算什麼英雄？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"영웅이라면 좀 더 화려하고 위엄 있는 복장이어야 하지 않겠어?","JPN":"英雄ならもっと華やかで威厳のある服装が相応しいんじゃないの？","ENG":"Shouldn't a hero wear something more elegant and dignified?","TWN":"作為英雄，應該穿得更華麗和威嚴一些，不是嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 그 말도 맞다 맞아.","JPN":"あはは、それもそうやな。","ENG":"Ah hah hah, you're right 'bout that.","TWN":"哈哈哈，你說的也對，沒錯。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래서, 영웅이 되고 싶은 이유는 그냥 멋있어서가?","JPN":"で、英雄になりたいんは単純に格好いいからなんか？","ENG":"So, do ya wanna be a hero 'cause it looks cool?","TWN":"所以，你想成為英雄的理由只是因為很帥嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당연하지! 카운터라면 그래야지!","JPN":"もちろん！　カウンターならそうなるべきでしょ？","ENG":"Of course! That's what Counters are supposed to be!","TWN":"那當然！制裁者就該這樣！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이왕이면 최고의 영웅! 사람들이 우러러보는 모습이 멋지지 않겠어?","JPN":"どうせなら最高の英雄！　人々に崇められる姿……素敵だと思わない？","ENG":"I want to be the strongest hero! Won't it be cool if people looked up to me?","TWN":"既然如此，就做最強的英雄吧！被人們仰望的樣子不是很帥氣嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"두고 봐. 나중에 졸업하면 진짜 영웅이 되어 보일 테니까!","JPN":"見てなさい。卒業したら本物の英雄になってみせるから！","ENG":"Just wait and see. I'll show you what a true hero looks like after I graduate!","TWN":"等著瞧吧。等我畢業後，一定會成為真正的英雄！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L7_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……내가 너에 대해 완벽히 아는 건 아닌지라 함부로 말은 못하겠는데,","JPN":"……あんたについて知らないことも多いから、こういうのもなんやけど…","ENG":"...I can't just tell ya 'cause I dunno everythin' 'bout ya,","TWN":"……我對你並不是完全了解，所以不敢輕易下結論。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"영웅이란 언제나 목숨을 걸어야 하는 운명이다.","JPN":"英雄っちゅうのは、いつだって命をかける運命やで。","ENG":"but heroes are always fated to risk their lives.","TWN":"英雄總是註定要冒生命危險的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그 어떤 위험이 닥친다 해도, 그럼에도 넌 영웅을 추구할 수 있겠나?","JPN":"どんな危険が押し寄せてきても、英雄を目指す覚悟、あんたにはあるんか？","ENG":"No matter the danger. Do ya still wanna be one?","TWN":"即使面臨任何危險，你仍然想成為英雄嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야? 지금 날 부정하겠다는 거야?","JPN":"何よ？　私のことを否定するつもり？","ENG":"Huh? Are you trying to say I'm wrong to admire heroes?","TWN":"什麼？你現在是在潑我冷水嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그, 그런 건 아니다. 내는 그저…….","JPN":"そ、そうやない。ウチはただ……","ENG":"N-no, nothing like that. I just...","TWN":"不，不是那樣的。我只是……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……아하하, 내가 쪼매 무거운 얘길 했네.","JPN":"あはは、重すぎる話持ち出したウチが悪かったな。","ENG":"...Ah hah hah. Guess the subject got too heavy.","TWN":"……哈哈哈，我剛才說了些沉重的話呢。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래…… 너라면 충분히 가능할 기다.","JPN":"そう……あんたにならできる。","ENG":"Yeah... I'm sure it'll be possible for you.","TWN":"……如果是你的話，是完全有可能的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내하곤 다르게…….</color>","JPN":"<color=#ffd34c>ウチとは違って……</color>","ENG":"<color=#ffd34c>Unlike me...</color>","TWN":"<color=#ffd34c>你與我不同……</color>"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};